-- Query: AccountReceivable3
SELECT Format([OrderDate],'mm-dd-yyyy') AS OrderDates, AccountReceivable1.CustomerID, AccountReceivable1.OrderNumber AS [Session], [Customers].[FirstName]+' '+[Customers].[LastName] AS Name, Format([Phone],'(000) 000-0000') AS [Phone Number], Customers.EMail, [AccountReceivable-1].Description, Format([AccountReceivable1].[OrderTotal]+[AccountReceivable1].[OrderTotalTax]+[AccountReceivable1].[ShippingTotal]+[AccountReceivable1].[ShippingTotalTax],'Currency') AS [Order T], IIf(IsNull([AccountReceivable1].[OrderTotal]),0,[AccountReceivable1].[OrderTotal]+[AccountReceivable1].[OrderTotalTax]+[AccountReceivable1].[ShippingTotal]+[AccountReceivable1].[ShippingTotalTax])-IIf(IsNull([AccountReceivable2-1].[DP]),0,[AccountReceivable2-1].[DP])-IIf(IsNull([AccountReceivable2].[TotalP]),0,[AccountReceivable2].[TotalP]) AS [Balance Due], Customers.WebPassword
FROM AccountReceivable2 RIGHT JOIN ([AccountReceivable2-1] RIGHT JOIN ((AccountReceivable1 RIGHT JOIN (Customers RIGHT JOIN Orders ON Customers.CustomerID = Orders.CustomerID) ON AccountReceivable1.OrderID = Orders.OrderID) LEFT JOIN [AccountReceivable-1] ON Orders.OrderID = [AccountReceivable-1].OrderID) ON [AccountReceivable2-1].OrderID = Orders.OrderID) ON AccountReceivable2.OrderID = Orders.OrderID
WHERE (((IIf(IsNull([AccountReceivable1].[OrderTotal]),0,[AccountReceivable1].[OrderTotal]+[AccountReceivable1].[OrderTotalTax]+[AccountReceivable1].[ShippingTotal]+[AccountReceivable1].[ShippingTotalTax])-IIf(IsNull([AccountReceivable2-1].[DP]),0,[AccountReceivable2-1].[DP])-IIf(IsNull([AccountReceivable2].[TotalP]),0,[AccountReceivable2].[TotalP]))>1));

